func solve(n int64, edges [][]int64, k int64) int64 {
	type DSU struct {
		parent []int64
		rank   []int64
		count  int64
	}

	func NewDSU(n int64) *DSU {
		parent := make([]int64, n)
		rank := make([]int64, n)
		for i := range parent {
			parent[i] = i
			rank[i] = 1
		}
		return &DSU{
			parent: parent,
			rank:   rank,
			count:  n,
		}
	}

	func (d *DSU) find(x int64) int64 {
		if d.parent[x] != x {
			d.parent[x] = d.find(d.parent[x])
		}
		return d.parent[x]
	}

	func (d *DSU) union(x, y int64) bool {
		xroot := d.find(x)
		yroot := d.find(y)
		if xroot == yroot {
			return false
		}
		if d.rank[xroot] < d.rank[yroot] {
			d.parent[xroot] = yroot
		} else {
			d.parent[yroot] = xroot
			if d.rank[xroot] == d.rank[yroot] {
				d.rank[xroot]++
			}
		}
		d.count--
		return true
	}

	func (d *DSU) countComponents() int64 {
		return d.count
	}

	if k == n {
		return 0
	}

	maxTime := int64(0)
	for _, e := range edges {
		if e[2] > maxTime {
			maxTime = e[2]
		}
	}

	low := int64(0)
	high := maxTime
	answer := maxTime

	check := func(t int64) bool {
		dsu := NewDSU(n)
		for _, e := range edges {
			if e[2] > t {
				u := e[0]
				v := e[1]
				dsu.union(u, v)
			}
		}
		return dsu.countComponents() >= k
	}

	for low <= high {
		mid := (low + high) / 2
		if check(mid) {
			answer = mid
			high = mid - 1
		} else {
			low = mid + 1
		}
	}

	return answer
}
